443	void apply_actions_and_update_state(const std::string& actions_str_final) {
444	    for (int i = 0; i < M_humans_global; ++i) {
445	        char action = actions_str_final[i];
446	        HumanInfo& human = humans_global_state[i]; 
447	        if (action != '.' && (action == 'u' || action == 'd' || action == 'l' || action == 'r')) {
448	            for(int k_dir=0; k_dir<4; ++k_dir){
449	                if (action == DIR_CHARS_BUILD[k_dir]) {
450	                    Point wall_pos = {human.pos.r + DIRS[k_dir].r, human.pos.c + DIRS[k_dir].c};
451	                    if (is_valid_point(wall_pos) && !is_impassable_grid_static[wall_pos.r][wall_pos.c]) { 
452	                        is_impassable_grid_static[wall_pos.r][wall_pos.c] = true;
453	                    }
454	                    break;
455	                }
456	            }
457	        }
458	    }
459	
460	    for (int i = 0; i < M_humans_global; ++i) {
461	        char action = actions_str_final[i];
462	        HumanInfo& human = humans_global_state[i]; 
463	        if (action != '.' && (action == 'U' || action == 'D' || action == 'L' || action == 'R')) {
464	            for(int k_dir=0; k_dir<4; ++k_dir){
465	                 if (action == DIR_CHARS_MOVE[k_dir]) {
466	                    Point next_pos = {human.pos.r + DIRS[k_dir].r, human.pos.c + DIRS[k_dir].c};
467	                    if (is_valid_point(next_pos) && !is_impassable_grid_static[next_pos.r][next_pos.c]) {
468	                         human.pos = next_pos;
469	                    } 
470	                    break;
471	                }
472	            }
473	        }
